using namespace adsk::core;
using namespace adsk::fusion;

Ptr ui;

extern "C" XI_EXPORT bool run(const char* context)
{
    Ptr app = Application::get();
    if (!app)
        return false;

    ui = app->userInterface();
    if (!ui)
        return false;

    Ptr documents = app->documents();
    if (!documents)
        return false;

    Ptr doc = documents->add(DocumentTypes::FusionDesignDocumentType);
    if (!doc)
        return false;

    Ptr product = app->activeProduct();
    if (!product)
        return false;

    Ptr design = product;
    if (!design)
        return false;

    // Get the root component.
    Ptr rootComp = design->rootComponent();
    if (!rootComp)
        return false;

    // Create a new sketch on the xy plane.
    Ptr sketches = rootComp->sketches();
    if (!sketches)
        return false;
    Ptr xyPlane = rootComp->xYConstructionPlane();
    if (!xyPlane)
        return false;
    Ptr sketch = sketches->add(xyPlane);
    if (!sketch)
        return false;

    // Create an object collection for the points.
    Ptr points = ObjectCollection::create();
    if (!points)
        return false;

    // Define the points the spline with fit through.
    points->add(Point3D::create(0, 0, 0));
    points->add(Point3D::create(5, 1, 0));
    points->add(Point3D::create(6, 4, 3));
    points->add(Point3D::create(7, 6, 6));
    points->add(Point3D::create(2, 3, 0));
    points->add(Point3D::create(0, 1, 0));

    // Create the spline.
    Ptr sketchCurves = sketch->sketchCurves();
    if (!sketchCurves)
        return false;
    Ptr splines = sketchCurves->sketchFittedSplines();
    if (!splines)
        return false;

    Ptr spline = splines->add(points);
    if (!spline)
        return false;

    // Get spline fit points
    Ptr fitPoints = spline->fitPoints();
    if (!fitPoints)
        return false;

    // Get the second fit point
    Ptr fitPoint = fitPoints->item(1);
    if (!fitPoint)
        return false;

    // If there is no the relative tangent handle, activate the tangent handle
    Ptr line = spline->getTangentHandle(fitPoint);
    if (line)
        return false;
    else
    {
        line = spline->activateTangentHandle(fitPoint);
        if (!line)
            return false;
    }

    // Get the tangent handle
    Ptr gottenLine = spline->getTangentHandle(fitPoint);
    if (!gottenLine)
        return false;

    // Delete the tangent handle
    bool isSuccess = gottenLine->deleteMe();
    if (!isSuccess)
        return false;

    // Activate the curvature handle
    // If the curvature handle activated. the relative tangentHandle is activated automatically
    Ptr activatedArc = spline->activateCurvatureHandle(fitPoint);
    if (!activatedArc)
        return false;

    // Get curvature handle and tangent handle
    Ptr gottenArc = spline->getCurvatureHandle(fitPoint);
    if (!gottenArc)
        return false;

    gottenLine = spline->getTangentHandle(fitPoint);
    if (!gottenLine)
        return false;

    // Delete curvature handle
    bool isDeleted = gottenArc->deleteMe();
    if (!isDeleted)
        return false;


    return true;
}
